/**
 * Apotheca Marketing Suite — Analytics Dashboard (React SPA)
 *
 * Tabs: Overview, Email Performance, SMS Performance, Subscriber Insights, Flow Analytics
 * All data via REST endpoints reading ams_analytics_daily.
 * CSV export on every table.
 */
(function () {
    'use strict';
    var el = wp.element.createElement;
    var useState = wp.element.useState;
    var useEffect = wp.element.useEffect;
    var Fragment = wp.element.Fragment;
    var api = wp.apiFetch;
    var __ = wp.i18n.__;
    var cfg = window.amsAnalytics || {};

    /* ── Helpers ── */
    function fmt(n) { return '$' + Number(n || 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }); }
    function pct(n) { return Number(n || 0).toFixed(1) + '%'; }
    function num(n) { return Number(n || 0).toLocaleString(); }

    function apiFetch(path, opts) {
        return api(Object.assign({ path: path.indexOf('/') === 0 ? path : cfg.restBase + '/' + path, headers: { 'X-WP-Nonce': cfg.nonce } }, opts || {}));
    }

    function downloadCSV(csv, filename) {
        var blob = new Blob([csv], { type: 'text/csv' });
        var url = URL.createObjectURL(blob);
        var a = document.createElement('a');
        a.href = url; a.download = filename; a.click();
        URL.revokeObjectURL(url);
    }

    /* ── MetricCard ── */
    function MetricCard(props) {
        return el('div', { className: 'ams-metric-card' },
            el('div', { className: 'label' }, props.label),
            el('div', { className: 'value' + (props.currency ? ' currency' : '') }, props.currency ? fmt(props.value).replace('$', '') : num(props.value))
        );
    }

    /* ── RangeSelector ── */
    function RangeSelector(props) {
        var ranges = [{ label: '7d', days: 7 }, { label: '30d', days: 30 }, { label: '90d', days: 90 }];
        return el('div', { className: 'ams-range-selector' },
            ranges.map(function (r) {
                return el('button', {
                    key: r.days, className: 'ams-range-btn' + (props.days === r.days ? ' active' : ''),
                    onClick: function () { props.onChange(r.days); }
                }, r.label);
            }),
            el('input', { type: 'date', value: props.from || '', onChange: function (e) { props.onCustom(e.target.value, props.to); }, style: { marginLeft: 8 } }),
            el('span', { style: { margin: '0 4px' } }, '–'),
            el('input', { type: 'date', value: props.to || '', onChange: function (e) { props.onCustom(props.from, e.target.value); } })
        );
    }

    /* ── ExportButton ── */
    function ExportButton(props) {
        function handleExport() {
            apiFetch('export?type=' + props.type).then(function (res) {
                if (res.csv) downloadCSV(res.csv, res.filename || 'export.csv');
            });
        }
        return el('button', { className: 'ams-export-btn', onClick: handleExport }, '\u2B07 Export CSV');
    }

    /* ── Simple Bar Chart ── */
    function BarChart(props) {
        var data = props.data || [];
        if (!data.length) return el('p', { className: 'ams-loading' }, 'No data');
        var max = Math.max.apply(null, data.map(function (d) { return Number(d.value) || 0; })) || 1;
        return el('div', { className: 'ams-bar-chart' },
            data.map(function (d, i) {
                var h = Math.max(2, (Number(d.value) / max) * 100);
                return el('div', {
                    key: i, className: 'ams-bar ' + (props.className || 'email'),
                    style: { height: h + '%' }, title: d.date + ': ' + fmt(d.value)
                }, data.length <= 31 ? el('span', { className: 'ams-bar-label' }, (d.date || '').slice(5)) : null);
            })
        );
    }

    /* ── Simple Data Table ── */
    function DataTable(props) {
        var cols = props.columns || [];
        var rows = props.rows || [];
        return el('table', { className: 'ams-data-table' },
            el('thead', null, el('tr', null, cols.map(function (c) { return el('th', { key: c.key }, c.label); }))),
            el('tbody', null, rows.map(function (row, i) {
                return el('tr', { key: i }, cols.map(function (c) {
                    var val = row[c.key];
                    if (c.format === 'currency') val = fmt(val);
                    else if (c.format === 'pct') val = pct(val);
                    else if (c.format === 'number') val = num(val);
                    return el('td', { key: c.key }, val);
                }));
            }))
        );
    }

    /* ══════════════════════════════════════════
       TAB: Overview
       ══════════════════════════════════════════ */
    function OverviewTab() {
        var _d = useState(30), days = _d[0], setDays = _d[1];
        var _f = useState(''), from = _f[0], setFrom = _f[1];
        var _t = useState(''), to = _t[0], setTo = _t[1];
        var _m = useState(null), metrics = _m[0], setMetrics = _m[1];
        var _rs = useState({ email: [], sms: [] }), revSeries = _rs[0], setRevSeries = _rs[1];
        var _sg = useState({ total: [], new: [] }), subGrowth = _sg[0], setSubGrowth = _sg[1];

        useEffect(function () {
            var q = from && to ? '?from=' + from + '&to=' + to : '?days=' + days;
            apiFetch('overview' + q).then(setMetrics);
            apiFetch('revenue-series?days=' + days).then(setRevSeries);
            apiFetch('subscriber-growth?days=' + days).then(setSubGrowth);
        }, [days, from, to]);

        if (!metrics) return el('div', { className: 'ams-loading' }, 'Loading...');

        return el(Fragment, null,
            el('h2', null, 'Analytics Overview'),
            el(RangeSelector, {
                days: days, from: from, to: to,
                onChange: function (d) { setDays(d); setFrom(''); setTo(''); },
                onCustom: function (f, t) { setFrom(f); setTo(t); }
            }),
            el('div', { className: 'ams-metric-cards' },
                el(MetricCard, { label: 'Revenue (Period)', value: metrics.period_revenue, currency: true }),
                el(MetricCard, { label: 'Revenue (All Time)', value: metrics.alltime_revenue, currency: true }),
                el(MetricCard, { label: 'Revenue (7d)', value: metrics.revenue_7d, currency: true }),
                el(MetricCard, { label: 'Email Revenue', value: metrics.email_revenue, currency: true }),
                el(MetricCard, { label: 'SMS Revenue', value: metrics.sms_revenue, currency: true }),
                el(MetricCard, { label: 'Active Subscribers', value: metrics.active_subscribers }),
                el(MetricCard, { label: 'Avg Order Value', value: metrics.avg_order_value, currency: true }),
                el(MetricCard, { label: 'Deliverability', value: metrics.deliverability + '%' })
            ),
            el('div', { className: 'ams-chart-row' },
                el('div', { className: 'ams-chart-container' },
                    el('h3', { className: 'ams-chart-title' }, 'Subscriber Growth (' + days + 'd)'),
                    el(BarChart, { data: subGrowth.new || [], className: 'email' })
                ),
                el('div', { className: 'ams-chart-container' },
                    el('h3', { className: 'ams-chart-title' }, 'Revenue by Channel (' + days + 'd)'),
                    el('div', { style: { marginBottom: 8 } },
                        el('span', { style: { display: 'inline-block', width: 12, height: 12, background: '#2271b1', marginRight: 4 } }), ' Email ',
                        el('span', { style: { display: 'inline-block', width: 12, height: 12, background: '#3bb77e', marginLeft: 12, marginRight: 4 } }), ' SMS'
                    ),
                    el(BarChart, { data: revSeries.email || [], className: 'email' })
                )
            )
        );
    }

    /* ══════════════════════════════════════════
       TAB: Email Performance
       ══════════════════════════════════════════ */
    function EmailTab() {
        var _d = useState([]), data = _d[0], setData = _d[1];
        useEffect(function () { apiFetch('email-performance').then(setData); }, []);

        var columns = [
            { key: 'name', label: 'Campaign / Flow' },
            { key: 'sent', label: 'Sent', format: 'number' },
            { key: 'delivered', label: 'Delivered', format: 'number' },
            { key: 'open_rate', label: 'Open Rate', format: 'pct' },
            { key: 'click_rate', label: 'Click Rate', format: 'pct' },
            { key: 'unsubscribe_rate', label: 'Unsub Rate', format: 'pct' },
            { key: 'revenue', label: 'Revenue', format: 'currency' },
            { key: 'revenue_per_send', label: 'Rev/Send', format: 'currency' }
        ];

        return el(Fragment, null,
            el('h2', null, 'Email Performance'),
            el(ExportButton, { type: 'email' }),
            el(DataTable, { columns: columns, rows: data })
        );
    }

    /* ══════════════════════════════════════════
       TAB: SMS Performance
       ══════════════════════════════════════════ */
    function SMSTab() {
        var _d = useState({ campaigns: [], delivery_trend: { sent: [], delivered: [] } }), data = _d[0], setData = _d[1];
        useEffect(function () { apiFetch('sms-performance').then(setData); }, []);

        var columns = [
            { key: 'name', label: 'Campaign' },
            { key: 'sent', label: 'Sent', format: 'number' },
            { key: 'delivered', label: 'Delivered', format: 'number' },
            { key: 'opt_out_rate', label: 'Opt-Out Rate', format: 'pct' },
            { key: 'revenue', label: 'Revenue', format: 'currency' }
        ];

        return el(Fragment, null,
            el('h2', null, 'SMS Performance'),
            el(ExportButton, { type: 'sms' }),
            el(DataTable, { columns: columns, rows: data.campaigns || [] }),
            el('div', { className: 'ams-chart-container' },
                el('h3', { className: 'ams-chart-title' }, 'Delivery Rate Trend (30d)'),
                el(BarChart, { data: data.delivery_trend ? data.delivery_trend.delivered : [], className: 'sms' })
            )
        );
    }

    /* ══════════════════════════════════════════
       TAB: Subscriber Insights
       ══════════════════════════════════════════ */
    function SubscriberTab() {
        var _d = useState(null), data = _d[0], setData = _d[1];
        useEffect(function () { apiFetch('subscriber-insights').then(setData); }, []);

        if (!data) return el('div', { className: 'ams-loading' }, 'Loading...');

        var COLORS = ['#2271b1', '#3bb77e', '#dba617', '#d63638', '#8c5e58', '#9b51e0', '#e36209', '#24837b'];
        function heatColor(count, max) {
            if (!count) return '#f0f0f0';
            var ratio = count / (max || 1);
            if (ratio > 0.6) return '#1a4f8b';
            if (ratio > 0.3) return '#2271b1';
            if (ratio > 0.1) return '#72aee6';
            return '#c3d9f0';
        }

        // RFM grid
        var rfmMax = Math.max.apply(null, (data.rfm_grid || []).map(function (c) { return c.count; }).concat([1]));
        var rfmCells = [];
        // Header row
        rfmCells.push(el('div', { key: 'h0', className: 'ams-rfm-header' }, 'R\\F'));
        for (var fi = 1; fi <= 5; fi++) rfmCells.push(el('div', { key: 'hf' + fi, className: 'ams-rfm-header' }, fi));
        for (var ri = 1; ri <= 5; ri++) {
            rfmCells.push(el('div', { key: 'r' + ri, className: 'ams-rfm-header' }, ri));
            for (var fj = 1; fj <= 5; fj++) {
                var cell = (data.rfm_grid || []).find(function (c) { return c.r === ri && c.f === fj; });
                var cnt = cell ? cell.count : 0;
                rfmCells.push(el('div', {
                    key: ri + '-' + fj, className: 'ams-rfm-cell',
                    style: { background: heatColor(cnt, rfmMax) },
                    title: 'R' + ri + ' F' + fj + ': ' + cnt + ' subscribers'
                }, cnt || ''));
            }
        }

        // Segment doughnut (CSS conic-gradient)
        var segments = data.segments || [];
        var totalSubs = segments.reduce(function (s, seg) { return s + Number(seg.subscriber_count || 0); }, 0);
        var gradientParts = [];
        var cumPct = 0;
        segments.forEach(function (seg, i) {
            var p = totalSubs > 0 ? (Number(seg.subscriber_count) / totalSubs) * 100 : 0;
            gradientParts.push(COLORS[i % COLORS.length] + ' ' + cumPct + '% ' + (cumPct + p) + '%');
            cumPct += p;
        });

        // Churn bar
        var churn = data.churn_risk || {};
        var churnMax = Math.max(churn.low || 0, churn.medium || 0, churn.high || 0, 1);

        // CLV histogram
        var clvBuckets = data.clv_buckets || {};
        var clvMax = Math.max.apply(null, Object.values(clvBuckets).concat([1]));

        return el(Fragment, null,
            el('h2', null, 'Subscriber Insights'),
            el('div', { className: 'ams-chart-row' },
                el('div', { className: 'ams-chart-container' },
                    el('h3', { className: 'ams-chart-title' }, 'RFM Heatmap'),
                    el('div', { className: 'ams-rfm-grid' }, rfmCells)
                ),
                el('div', { className: 'ams-chart-container' },
                    el('h3', { className: 'ams-chart-title' }, 'Segments'),
                    el('div', {
                        className: 'ams-doughnut',
                        style: { background: gradientParts.length ? 'conic-gradient(' + gradientParts.join(', ') + ')' : '#f0f0f0' }
                    }, el('div', { className: 'ams-doughnut-center' }, num(totalSubs))),
                    el('div', { className: 'ams-legend' },
                        segments.map(function (seg, i) {
                            return el('div', { key: i, className: 'ams-legend-item' },
                                el('div', { className: 'ams-legend-swatch', style: { background: COLORS[i % COLORS.length] } }),
                                seg.name + ' (' + num(seg.subscriber_count) + ')'
                            );
                        })
                    )
                )
            ),
            el('div', { className: 'ams-chart-row' },
                el('div', { className: 'ams-chart-container' },
                    el('h3', { className: 'ams-chart-title' }, 'Churn Risk Distribution'),
                    ['low', 'medium', 'high'].map(function (level) {
                        var val = churn[level] || 0;
                        var color = level === 'low' ? '#3bb77e' : level === 'medium' ? '#dba617' : '#d63638';
                        return el('div', { key: level, style: { display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 } },
                            el('span', { style: { width: 60, fontWeight: 600, textTransform: 'capitalize' } }, level),
                            el('div', { style: { flex: 1, height: 24, background: '#f0f0f0', borderRadius: 3 } },
                                el('div', { style: { width: (val / churnMax * 100) + '%', height: '100%', background: color, borderRadius: 3 } })
                            ),
                            el('span', { style: { width: 60, textAlign: 'right' } }, num(val))
                        );
                    })
                ),
                el('div', { className: 'ams-chart-container' },
                    el('h3', { className: 'ams-chart-title' }, 'CLV Distribution'),
                    Object.keys(clvBuckets).map(function (bucket) {
                        var val = clvBuckets[bucket] || 0;
                        return el('div', { key: bucket, style: { display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 } },
                            el('span', { style: { width: 80, fontSize: 12 } }, '$' + bucket),
                            el('div', { style: { flex: 1, height: 20, background: '#f0f0f0', borderRadius: 3 } },
                                el('div', { style: { width: (val / clvMax * 100) + '%', height: '100%', background: '#2271b1', borderRadius: 3 } })
                            ),
                            el('span', { style: { width: 50, textAlign: 'right', fontSize: 12 } }, num(val))
                        );
                    })
                )
            )
        );
    }

    /* ══════════════════════════════════════════
       TAB: Flow Analytics
       ══════════════════════════════════════════ */
    function FlowTab() {
        var _d = useState([]), flows = _d[0], setFlows = _d[1];
        useEffect(function () { apiFetch('flow-analytics').then(setFlows); }, []);

        if (!flows.length) return el('div', { className: 'ams-loading' }, 'No flow data');

        return el(Fragment, null,
            el('h2', null, 'Flow Analytics'),
            flows.map(function (flow) {
                var maxEnrolled = flow.enrolled || 1;
                return el('div', { key: flow.id, className: 'ams-chart-container' },
                    el('h3', { className: 'ams-chart-title' }, flow.name),
                    el('div', { style: { display: 'flex', gap: 16, marginBottom: 12 } },
                        el('span', null, 'Enrolled: ', el('strong', null, num(flow.enrolled))),
                        el('span', null, 'Completed: ', el('strong', null, num(flow.completed))),
                        el('span', null, 'Exited: ', el('strong', null, num(flow.exited)))
                    ),
                    el('div', { className: 'ams-funnel' },
                        el('div', { className: 'ams-funnel-step' },
                            el('span', { className: 'ams-funnel-label' }, 'Enrolled'),
                            el('div', { className: 'ams-funnel-bar', style: { width: '100%' } }),
                            el('span', { className: 'ams-funnel-stat' }, num(flow.enrolled))
                        ),
                        (flow.steps || []).map(function (step) {
                            var w = maxEnrolled > 0 ? Math.max(2, (step.sent / maxEnrolled) * 100) : 2;
                            return el('div', { key: step.step_order, className: 'ams-funnel-step' },
                                el('span', { className: 'ams-funnel-label' }, 'Step ' + step.step_order + ' (' + step.step_type + ')'),
                                el('div', { className: 'ams-funnel-bar' + (step.highlight ? ' warn' : ''), style: { width: w + '%' } }),
                                el('span', { className: 'ams-funnel-stat' },
                                    num(step.sent) + ' sent' +
                                    (step.dropoff > 0 ? ' (' + pct(step.dropoff) + ' drop-off)' : '')
                                )
                            );
                        })
                    )
                );
            })
        );
    }

    /* ══════════════════════════════════════════
       MAIN APP
       ══════════════════════════════════════════ */
    function App() {
        var _t = useState('overview'), tab = _t[0], setTab = _t[1];

        var TABS = [
            { key: 'overview', label: 'Overview' },
            { key: 'email', label: 'Email Performance' },
            { key: 'sms', label: 'SMS Performance' },
            { key: 'subscribers', label: 'Subscriber Insights' },
            { key: 'flows', label: 'Flow Analytics' }
        ];

        var content;
        switch (tab) {
            case 'overview': content = el(OverviewTab); break;
            case 'email': content = el(EmailTab); break;
            case 'sms': content = el(SMSTab); break;
            case 'subscribers': content = el(SubscriberTab); break;
            case 'flows': content = el(FlowTab); break;
            default: content = el(OverviewTab);
        }

        return el(Fragment, null,
            el('h1', { style: { marginBottom: 16 } }, 'Apotheca Marketing Analytics'),
            el('div', { className: 'ams-analytics-tabs' },
                TABS.map(function (t) {
                    return el('button', {
                        key: t.key,
                        className: 'ams-analytics-tab' + (tab === t.key ? ' active' : ''),
                        onClick: function () { setTab(t.key); }
                    }, t.label);
                })
            ),
            content
        );
    }

    /* ── Mount ── */
    var root = document.getElementById('ams-analytics-root');
    if (root) {
        if (wp.element.createRoot) {
            wp.element.createRoot(root).render(el(App));
        } else {
            wp.element.render(el(App), root);
        }
    }
})();
